const body = $json.body ?? $json;
const fields = ['name', 'email', 'company', 'message'];
for (const field of fields) {
  if (typeof body[field] !== 'string' || !body[field].trim()) {
    throw new Error(`Missing required field: ${field}`);
  }
}
const email = body.email.trim();
if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
  throw new Error('Invalid email address');
}
const escapeHtml = (value) => value
  .trim()
  .replaceAll('&', '&amp;')
  .replaceAll('<', '&lt;')
  .replaceAll('>', '&gt;')
  .replaceAll('\"', '&quot;')
  .replaceAll("'", '&#039;');
const name = escapeHtml(body.name.slice(0, 120));
const company = escapeHtml(body.company.slice(0, 160));
const message = escapeHtml(body.message.slice(0, 3000)).replaceAll('\n', '<br>');
return [{ json: {
  name,
  email,
  company,
  message,
  html: `<h1>New portfolio career enquiry</h1><p><strong>Name:</strong> ${name}</p><p><strong>Email:</strong> ${escapeHtml(email)}</p><p><strong>Company:</strong> ${company}</p><p><strong>Message:</strong></p><p>${message}</p>`
} }];
